import{_ as t,o as e,c as p,a as _}from"./app.7f9bd173.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"article/2022.5.9.md"}'),a={name:"article/2022.5.9.md"},o=_("<h1>柳絮 阴雨 街道</h1><p>作者: 孙飞</p><p>日期: 2022.5.9</p><hr><p>五月初的柳絮被一场突如其来的阴雨给冲刷掉 想来立夏后的第一场夏雨也是对过去的冲刷 同时也是新季的开始 可是新的开始没有等来立夏的鸟语花香 疫情便悄然而至 并肆意横行 <p>空无一人的街道 望着红条幅的防疫警示语 闻着压抑的空气 听着丁香晓晓的夏雨 回想着小时候一起在夏雨中嬉闹的场景 瞬间内心感慨万分 我实在不忍接受现在的一切 时光到底带给我了什么 可是又有什么办法的 你没有办法让时间停止的</p><p>路边的小石子被夏雨一遍又一遍地冲刷 小鸟在地上跳来跳去 不知道在寻找着什么 我走在林间的小道 不知道去往哪里 总是在前往梦想的路程中而忘记了初衷 背负了内心却仍走的坦荡 我为自己的自私 胆小而羞愧万分</p><p>向来孤独的人最多情 我渴望逃离世间的烦扰错杂 我期待美好的爱情 但我不敢去表达 我内心的想法一一败退于现实的软弱 怕了太多 就不敢了</p><p>内心明白很多道理 依然做不到 大概时光教会了我 但我依然错过了时光 夏雨下不停 阴雨就这样盘旋我心头良久 我觉得做一个人真的很难 我不会控制人的七情六欲 也处理不了复杂的人际关系 更不会创造出有意义的价值</p><p>我时常窥视别人的生活圈 然后经常感概别人的生活有多么美好 有那么一段时间我怀疑自己是不是大脑有病了 即使我很清楚的明白 有些行为毫无意义 我为什么总是控制不住地去做呢</p><p>此时此刻 我都怀疑我为什么感概这么多呢 我是否太过于矫情 说这些的意义是什么呢 ?是为了安抚我那一丝价值也没有的人生吗?是欺骗内心然后睡得踏实吗?是为了什么?为了感慨夏雨的美好吗? 活了这么久 我到底是为了什么?</p><p>夏雨你下吧 即使阴雨布满灰色的天空 我想 院中的石榴树此刻是开心的 你说呢</p></p>",5),r=[o];function c(s,n,i,d,l,h){return e(),p("div",null,r)}const T=t(a,[["render",c]]);export{f as __pageData,T as default};
